use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use data_encoding::HEXLOWER;use std::marker::PhantomData;pub struct HexDecoder;impl Crack for Decoder<HexDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let cleaned = text.trim().replace([' ', '\n', '\r', '\t', '0', 'x', 'X'], "");        if let Ok(decoded_bytes) = HEXLOWER.decode(cleaned.as_bytes()) {            if let Ok(decoded_str) = String::from_utf8(decoded_bytes) {                if check_string_success(&decoded_str, text) {                    let check_result = checker.check_text(&decoded_str);                    if check_result.is_identified {                        result.success = true;                        result.unencrypted_text = Some(vec![decoded_str]);                        result.checker_name = check_result.checker_name;                        return result;                    }                }            }        }        let cleaned_lower = text.trim().replace([' ', '\n', '\r', '\t'], "").to_lowercase();        let cleaned_no_prefix = cleaned_lower.strip_prefix("0x").unwrap_or(&cleaned_lower);        if let Ok(decoded_bytes) = HEXLOWER.decode(cleaned_no_prefix.as_bytes()) {            if let Ok(decoded_str) = String::from_utf8(decoded_bytes) {                if check_string_success(&decoded_str, text) {                    let check_result = checker.check_text(&decoded_str);                    if check_result.is_identified {                        result.success = true;                        result.unencrypted_text = Some(vec![decoded_str]);                        result.checker_name = check_result.checker_name;                        return result;                    }                }            }        }        result    }    fn get_name(&self) -> &'static str { "Hex" }    fn get_popularity(&self) -> f32 { 0.8 }    fn get_tags(&self) -> &'static [&'static str] { &["hex", "decoder", "base"] }    fn get_description(&self) -> &'static str { "Hexadecimal (hex) is a numeral system that represents binary data in base-16." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Hexadecimal" }}impl Decoder<HexDecoder> {    pub fn new() -> Self {        Decoder {            name: "Hex",            description: "Hexadecimal (hex) is a numeral system that represents binary data in base-16.",            link: "https://en.wikipedia.org/wiki/Hexadecimal",            tags: vec!["hex", "decoder", "base"],            popularity: 0.8,            phantom: PhantomData,        }    }}



